/* Suggested markup: <div class="uiwiki-measured-version-coach" tabindex="0"><span>Measured Version Coach</span></div> */
.uiwiki-measured-version-coach {
  display: grid;
  place-items: center;
  min-height: 11rem;
  padding: 1.25rem;
  border: 1px solid #ececee;
  border-radius: 22px;
  background: #ffffff;
  color: #111111;
  font: 700 1rem/1.2 Inter, system-ui, sans-serif;
  box-shadow: 0 2px 16px rgba(0, 0, 0, 0.04);
  transition: transform 240ms cubic-bezier(.22, 1, .36, 1), box-shadow 240ms ease;
}
.uiwiki-measured-version-coach > span {
  padding: .75rem 1rem;
  border-radius: 999px;
  background: #d8f34e;
  animation: measured_version_coach 1.8s ease-in-out infinite alternate;
}
.uiwiki-measured-version-coach:hover,
.uiwiki-measured-version-coach:focus-visible {
  transform: translateY(-3px);
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.08);
}
@keyframes measured_version_coach {
  from { transform: translateY(0) scale(1); }
  to { transform: translateY(-4px) scale(1.025); }
}
@media (prefers-reduced-motion: reduce) {
  .uiwiki-measured-version-coach, .uiwiki-measured-version-coach > span { animation: none; transition: none; }
}
